from collections import deque

class RecentCounter:
    def __init__(self):
        self.q = deque()

    def ping(self, t: int) -> int:
        self.q.append(t)
        while self.q[0] < t - 3000:
            self.q.popleft()
        return len(self.q)

if __name__ == '__main__':
    recentCounter = RecentCounter()
    print(recentCounter.ping(1))     # return 1
    print(recentCounter.ping(100))   # return 2
    print(recentCounter.ping(3001))  # return 3
    print(recentCounter.ping(3002))  # return 3
